import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as n,e}from"./app-be253e4c.js";const o={},c=e(`<h1 id="docker-compose" tabindex="-1"><a class="header-anchor" href="#docker-compose" aria-hidden="true">#</a> Docker-Compose</h1><h3 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h3><p>Docker-Compose项目是Docker官方的开源项目，负责实现对Docker容器集群的快速编排。</p><p>Docker-Compose将所管理的容器分为三层，分别是:</p><ul><li>工程（project）</li><li>服务（service）</li><li>容器（container）</li></ul><p>Docker-Compose运行目录下的所有文件（docker-compose.yml，extends文件或环境变量文件等）组成一个工程，若无特殊指定工程名即为当前目录名。 一个工程当中可包含多个服务，每个服务中定义了容器运行的镜像，参数，依赖。</p><p>一个服务当中可包括多个容器实例，Docker-Compose并没有解决负载均衡的问题，因此需要借助其它工具实现服务发现及负载均衡。</p><p>Docker-Compose的工程配置文件默认为docker-compose.yml，可通过环境变量COMPOSE_FILE或-f参数自定义配置文件，其定义了多个有依赖关系的服务及每个服务运行的容器。 使用一个Dockerfile模板文件，可以让用户很方便的定义一个单独的应用容器。</p><p>在工作中，经常会碰到需要多个容器相互配合来完成某项任务的情况。例如要实现一个Web项目，除了Web服务容器本身，往往还需要再加上后端的数据库服务容器，甚至还包括负载均衡容器等。</p><p>Docker-Compose允许用户通过一个单独的docker-compose.yml模板文件（YAML 格式）来定义一组相关联的应用容器为一个项目</p><p>Docker-Compose项目由Python编写，调用Docker服务提供的API来对容器进行管理;只要所操作的平台支持Docker API，就可以在其上利用Compose来进行编排管理。</p><h3 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h3><p>安装方法一：</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>
<span class="token comment">## 下载并安装</span>
<span class="token function">curl</span> <span class="token parameter variable">-L</span> https://github.com/docker/compose/releases/download/1.23.0-rc3/docker-compose-<span class="token variable"><span class="token variable">\`</span><span class="token function">uname</span> <span class="token parameter variable">-s</span><span class="token variable">\`</span></span>-<span class="token variable"><span class="token variable">\`</span><span class="token function">uname</span> <span class="token parameter variable">-m</span><span class="token variable">\`</span></span> <span class="token punctuation">\\</span> 
<span class="token parameter variable">-o</span> /usr/local/bin/docker-compose
<span class="token comment">## 设置权限</span>
<span class="token function">chmod</span> +x /usr/local/bin/docker-compose
<span class="token comment">## 查看版本</span>
<span class="token function">docker-compose</span> version

</code></pre></div><p>安装方法二：</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 安装pip</span>
yum  <span class="token function">install</span> epel-release python-pip <span class="token parameter variable">-y</span>

<span class="token comment">## 确认版本</span>
pip <span class="token parameter variable">--version</span>

<span class="token comment">## 更新pip</span>
pip <span class="token function">install</span> <span class="token parameter variable">--upgrade</span> pip

<span class="token comment">## 安装docker-compose</span>
pip <span class="token function">install</span> <span class="token function">docker-compose</span>

<span class="token comment">## 查看版本</span>
<span class="token function">docker-compose</span> version

</code></pre></div><p>安装方法三：</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>
<span class="token comment">## 脚本安装</span>
<span class="token function">curl</span> <span class="token parameter variable">-L</span> https://raw.githubusercontent.com/docker/compose/<span class="token variable"><span class="token variable">$(</span><span class="token function">docker-compose</span> version <span class="token parameter variable">--short</span><span class="token variable">)</span></span>/contrib/completion/bash/docker-compose <span class="token operator">&gt;</span> /etc/bash_completion.d/docker-compose

</code></pre></div><h3 id="卸载" tabindex="-1"><a class="header-anchor" href="#卸载" aria-hidden="true">#</a> 卸载</h3><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 如果是二进制包方式安装的，删除二进制文件即可：</span>
<span class="token function">sudo</span> <span class="token function">rm</span> /usr/local/bin/docker-compose
<span class="token comment">## 如果通过Python pip工具安装的，则执行如下命令删除：</span>
<span class="token function">sudo</span> pip uninstall <span class="token function">docker-compose</span>
</code></pre></div><h3 id="常用命令" tabindex="-1"><a class="header-anchor" href="#常用命令" aria-hidden="true">#</a> 常用命令</h3><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> <span class="token punctuation">[</span>-f <span class="token operator">&lt;</span>arg<span class="token operator">&gt;</span><span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>COMMAND<span class="token punctuation">]</span> <span class="token punctuation">[</span>ARGS<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>命令选项如下：</p><ul><li><code>-f, –file</code>: FILE指定Compose模板文件，默认为docker-compose.yml，可以多次指定。</li><li><code>-p，–project-name</code> : NAME指定项目名称，默认将使用所在目录名称作为项目名。</li><li><code>-x-network-driver</code> : 使用Docker的可拔插网络后端特性（需要Docker 1.9+版本）</li><li><code>-x-network-driver</code> : DRIVER指定网络后端的驱动，默认为bridge（需要Docker 1.9+版本）</li><li><code>-verbose</code> : 输出更多调试信息</li><li><code>-v，–version</code> : 打印版本并退出</li></ul><h4 id="docker-compose-up" tabindex="-1"><a class="header-anchor" href="#docker-compose-up" aria-hidden="true">#</a> docker-compose up</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> up <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>--scale <span class="token assign-left variable">SERVICE</span><span class="token operator">=</span>NUM<span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li><code>-d</code> : 在后台运行服务容器</li><li><code>–no-color</code> : 不使用颜色来区分不同的服务的控制输出</li><li><code>–no-deps</code> : 不启动服务所链接的容器</li><li><code>–force-recreate</code> : 强制重新创建容器，不能与–no-recreate同时使用</li><li><code>–no-recreate</code> : 如果容器已经存在，则不重新创建，不能与–force-recreate同时使用</li><li><code>–no-build</code> : 不自动构建缺失的服务镜像</li><li><code>–build</code> : 在启动容器前构建服务镜像</li><li><code>–abort-on-container-exit</code> : 停止所有容器，如果任何一个容器被停止，不能与-d同时使用</li><li><code>-t, –timeout TIMEOUT</code> : 停止容器时候的超时（默认为10秒）</li><li><code>–remove-orphans</code> : 删除服务中没有在compose文件中定义的容器</li><li><code>–scale SERVICE=NUM</code> : 设置服务运行容器的个数，将覆盖在compose中通过scale指定的参数</li><li><code>-f</code> : 指定使用的Compose模板文件，默认为docker-compose.yml，可以多次指定。</li></ul><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 启动所有服务</span>
<span class="token function">docker-compose</span> up

<span class="token comment">## 在后台所有启动服务</span>
<span class="token function">docker-compose</span> up <span class="token parameter variable">-d</span>

<span class="token comment">## 指定模板配置文件后台启动所有服务</span>
<span class="token function">docker-compose</span> <span class="token parameter variable">-f</span> docker-compose.yml up <span class="token parameter variable">-d</span>
</code></pre></div><h4 id="docker-compose-ps" tabindex="-1"><a class="header-anchor" href="#docker-compose-ps" aria-hidden="true">#</a> docker-compose ps</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> <span class="token function">ps</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>

<span class="token comment">## 列出项目中目前的所有容器</span>
<span class="token function">docker-compose</span> <span class="token function">ps</span>
</code></pre></div><h4 id="docker-compose-stop" tabindex="-1"><a class="header-anchor" href="#docker-compose-stop" aria-hidden="true">#</a> docker-compose stop</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> stop <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>

<span class="token comment">## 停止正在运行的容器，再次启动</span>
<span class="token function">docker-compose</span> start 
</code></pre></div><p>选项包括：</p><ul><li><code>-t, –timeout TIMEOUT</code> : 停止容器时候的超时（默认为10秒）</li></ul><h4 id="docker-compose-down" tabindex="-1"><a class="header-anchor" href="#docker-compose-down" aria-hidden="true">#</a> docker-compose down</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 停止和删除容器、网络、卷、镜像</span>
<span class="token function">docker-compose</span> down <span class="token punctuation">[</span>options<span class="token punctuation">]</span>

<span class="token comment">## 停用移除所有容器以及网络相关</span>
<span class="token function">docker-compose</span> down
</code></pre></div><p>选项包括：</p><ul><li><code>–rmi type</code> : 删除镜像，类型必须是：all，删除compose文件中定义的所有镜像；local，删除镜像名为空的镜像</li><li><code>-v, –volumes</code> : 删除已经在compose文件中定义的和匿名的附在容器上的数据卷</li><li><code>–remove-orphans</code> : 删除服务中没有在compose中定义的容器</li></ul><h4 id="docker-compose-logs" tabindex="-1"><a class="header-anchor" href="#docker-compose-logs" aria-hidden="true">#</a> docker-compose logs</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 查看服务容器的输出。默认情况下，docker-compose将对不同的服务输出使用不同的颜色来区分。可以通过–no-color来关闭颜色。</span>
<span class="token function">docker-compose</span> logs <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>

<span class="token comment">## 查看服务容器的输出</span>
<span class="token function">docker-compose</span> logs
</code></pre></div><h4 id="docker-compose-build" tabindex="-1"><a class="header-anchor" href="#docker-compose-build" aria-hidden="true">#</a> docker-compose build</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 构建（重新构建）项目中的服务容器。</span>
<span class="token function">docker-compose</span> build <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>--build-arg <span class="token assign-left variable">key</span><span class="token operator">=</span>val<span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li><code>–compress</code> : 通过gzip压缩构建上下环境</li><li><code>–force-rm</code> : 删除构建过程中的临时容器</li><li><code>–no-cache</code> : 构建镜像过程中不使用缓存</li><li><code>–pull</code> : 始终尝试通过拉取操作来获取更新版本的镜像</li><li><code>-m, –memory</code> : MEM为构建的容器设置内存大小</li><li><code>- –build-arg key=val</code> : 为服务设置build-time变量</li></ul><p>服务容器一旦构建后，将会带上一个标记名。可以随时在项目目录下运行docker-compose build来重新构建服务</p><h4 id="docker-compose-pull" tabindex="-1"><a class="header-anchor" href="#docker-compose-pull" aria-hidden="true">#</a> docker-compose pull</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 拉取服务依赖的镜像</span>
<span class="token function">docker-compose</span> pull <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>

<span class="token comment">## 拉取服务依赖的镜像</span>
<span class="token function">docker-compose</span> pull
</code></pre></div><p>选项包括：</p><ul><li><code>–ignore-pull-failures</code> : 忽略拉取镜像过程中的错误</li><li><code>–parallel</code> : 多个镜像同时拉取</li><li><code>–quiet</code> : 拉取镜像过程中不打印进度信息</li></ul><h4 id="docker-compose-restart" tabindex="-1"><a class="header-anchor" href="#docker-compose-restart" aria-hidden="true">#</a> docker-compose restart</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 重启项目中的服务</span>
<span class="token function">docker-compose</span> restart <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li><code>-t, –timeout TIMEOUT</code> ：指定重启前停止容器的超时（默认为10秒）</li></ul><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 重启项目中的所有服务</span>
<span class="token function">docker-compose</span> restart
</code></pre></div><h4 id="docker-compose-rm" tabindex="-1"><a class="header-anchor" href="#docker-compose-rm" aria-hidden="true">#</a> docker-compose rm</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 删除所有（停止状态的）服务容器</span>
<span class="token function">docker-compose</span> <span class="token function">rm</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li><code>–f, –force</code> : 强制直接删除，包括非停止状态的容器</li><li><code>-v</code> : 删除容器所挂载的数据卷</li></ul><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 删除所有（停止状态的）服务容器 推荐先执行docker-compose stop命令来停止容器。</span>
<span class="token function">docker-compose</span> <span class="token function">rm</span>
</code></pre></div><h4 id="docker-compose-start" tabindex="-1"><a class="header-anchor" href="#docker-compose-start" aria-hidden="true">#</a> docker-compose start</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 启动已经存在的服务容器</span>
<span class="token function">docker-compose</span> start <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
<span class="token function">docker-compose</span> start
</code></pre></div><h4 id="docker-compose-run" tabindex="-1"><a class="header-anchor" href="#docker-compose-run" aria-hidden="true">#</a> docker-compose run</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 在指定服务上执行一个命令</span>
<span class="token function">docker-compose</span> run <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>-v VOLUME<span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>-p PORT<span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>-e <span class="token assign-left variable">KEY</span><span class="token operator">=</span>VAL<span class="token punctuation">..</span>.<span class="token punctuation">]</span> SERVICE <span class="token punctuation">[</span>COMMAND<span class="token punctuation">]</span> <span class="token punctuation">[</span>ARGS<span class="token punctuation">..</span>.<span class="token punctuation">]</span>

<span class="token comment">## 在指定容器上执行一个ping命令</span>
<span class="token function">docker-compose</span> run ubuntu <span class="token function">ping</span> www.baidu.com
</code></pre></div><h4 id="docker-compose-scale" tabindex="-1"><a class="header-anchor" href="#docker-compose-scale" aria-hidden="true">#</a> docker-compose scale</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 设置指定服务运行的容器个数。通过service=num的参数来设置数量</span>
<span class="token function">docker-compose</span> scale <span class="token assign-left variable">web</span><span class="token operator">=</span><span class="token number">3</span> <span class="token assign-left variable">db</span><span class="token operator">=</span><span class="token number">2</span>
</code></pre></div><h4 id="docker-compose-pause" tabindex="-1"><a class="header-anchor" href="#docker-compose-pause" aria-hidden="true">#</a> docker-compose pause</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 暂停一个服务容器</span>
<span class="token function">docker-compose</span> pause <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><h4 id="docker-compose-kill" tabindex="-1"><a class="header-anchor" href="#docker-compose-kill" aria-hidden="true">#</a> docker-compose kill</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 通过发送SIGKILL信号来强制停止服务容器</span>
<span class="token function">docker-compose</span> <span class="token function">kill</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>支持通过-s参数来指定发送的信号， 例如通过如下指令发送SIGINT信号：</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> <span class="token function">kill</span> <span class="token parameter variable">-s</span> SIGINT
</code></pre></div><h4 id="docker-compose-config" tabindex="-1"><a class="header-anchor" href="#docker-compose-config" aria-hidden="true">#</a> docker-compose config</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 验证并查看compose文件配置。</span>
<span class="token function">docker-compose</span> config <span class="token punctuation">[</span>options<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li><code>–resolve-image-digests</code> : 将镜像标签标记为摘要</li><li><code>-q, –quiet</code> : 只验证配置，不输出。 当配置正确时，不输出任何内容，当文件配置错误，输出错误信息</li><li><code>–services</code> : 打印服务名，一行一个</li><li><code>–volumes</code> : 打印数据卷名，一行一个</li></ul><h4 id="docker-compose-create" tabindex="-1"><a class="header-anchor" href="#docker-compose-create" aria-hidden="true">#</a> docker-compose create</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 为服务创建容器</span>
<span class="token function">docker-compose</span> create <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li>–force-recreate : 重新创建容器，即使配置和镜像没有改变，不兼容–no-recreate参数</li><li>–no-recreate : 如果容器已经存在，不需要重新创建，不兼容–force-recreate参数</li><li>–no-build : 不创建镜像，即使缺失</li><li>–build : 创建容器前，生成镜像</li></ul><h4 id="docker-compose-exec" tabindex="-1"><a class="header-anchor" href="#docker-compose-exec" aria-hidden="true">#</a> docker-compose exec</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker-compose</span> <span class="token builtin class-name">exec</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> SERVICE COMMAND <span class="token punctuation">[</span>ARGS<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li>-d : 分离模式，后台运行命令。</li><li>–privileged : 获取特权。</li><li>–user USER : 指定运行的用户。</li><li>-T : 禁用分配TTY，默认docker-compose exec分配TTY。</li><li>–index=index : 当一个服务拥有多个容器时，可通过该参数登陆到该服务下的任何服务，例如：docker-compose exec –index=1 web /bin/bash ，web服务中包含多个容器</li></ul><h4 id="docker-compose-port" tabindex="-1"><a class="header-anchor" href="#docker-compose-port" aria-hidden="true">#</a> docker-compose port</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 显示某个容器端口所映射的公共端口</span>
<span class="token function">docker-compose</span> port <span class="token punctuation">[</span>options<span class="token punctuation">]</span> SERVICE PRIVATE_PORT
</code></pre></div><p>选项包括：</p><ul><li>–protocol=proto : 指定端口协议，TCP（默认值）或者UDP</li><li>–index=index : 如果同意服务存在多个容器，指定命令对象容器的序号（默认为1）</li></ul><h4 id="docker-compose-push" tabindex="-1"><a class="header-anchor" href="#docker-compose-push" aria-hidden="true">#</a> docker-compose push</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 推送服务依的镜像</span>
<span class="token function">docker-compose</span> push <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><p>选项包括：</p><ul><li>–ignore-push-failures : 忽略推送镜像过程中的错误</li></ul><h4 id="docker-compose-unpause" tabindex="-1"><a class="header-anchor" href="#docker-compose-unpause" aria-hidden="true">#</a> docker-compose unpause</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 恢复处于暂停状态中的服务。</span>
<span class="token function">docker-compose</span> unpause <span class="token punctuation">[</span>SERVICE<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre></div><h4 id="docker-compose-version" tabindex="-1"><a class="header-anchor" href="#docker-compose-version" aria-hidden="true">#</a> docker-compose version</h4><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token comment">## 打印版本信息。</span>
<span class="token function">docker-compose</span> version
</code></pre></div><h3 id="docker-compose模板文件" tabindex="-1"><a class="header-anchor" href="#docker-compose模板文件" aria-hidden="true">#</a> Docker-Compose模板文件</h3><h4 id="简介-1" tabindex="-1"><a class="header-anchor" href="#简介-1" aria-hidden="true">#</a> 简介</h4><p>Compose允许用户通过一个docker-compose.yml模板文件（YAML 格式）来定义一组相关联的应用容器为一个项目（project）。 Compose模板文件是一个定义服务、网络和卷的YAML文件。Compose模板文件默认路径是当前目录下的docker-compose.yml，可以使用.yml或.yaml作为文件扩展名。 Docker-Compose标准模板文件应该包含version、services、networks 三大部分，最关键的是services和networks两个部分。</p><div class="language-yaml" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&#39;2&#39;</span>
<span class="token key atrule">services</span><span class="token punctuation">:</span>
  <span class="token key atrule">web</span><span class="token punctuation">:</span> 
    <span class="token key atrule">image</span><span class="token punctuation">:</span> dockercloud/hello<span class="token punctuation">-</span>world
    <span class="token key atrule">ports</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> <span class="token number">8080</span>
    <span class="token key atrule">networks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> front<span class="token punctuation">-</span>tier
    <span class="token punctuation">-</span> back<span class="token punctuation">-</span>tier
  <span class="token key atrule">redis</span><span class="token punctuation">:</span>
    <span class="token key atrule">image</span><span class="token punctuation">:</span> redis
    <span class="token key atrule">links</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> web
    <span class="token key atrule">networks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> back<span class="token punctuation">-</span>tier
  <span class="token key atrule">lb</span><span class="token punctuation">:</span>
    <span class="token key atrule">image</span><span class="token punctuation">:</span> dockercloud/haproxy
    <span class="token key atrule">ports</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> <span class="token datetime number">80:80</span>
    <span class="token key atrule">links</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> web
    <span class="token key atrule">networks</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> front<span class="token punctuation">-</span>tier
      <span class="token punctuation">-</span> back<span class="token punctuation">-</span>tier
    <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> /var/run/docker.sock<span class="token punctuation">:</span>/var/run/docker.sock
<span class="token key atrule">networks</span><span class="token punctuation">:</span>
  <span class="token key atrule">front-tier</span><span class="token punctuation">:</span>
    <span class="token key atrule">driver</span><span class="token punctuation">:</span> bridge
  <span class="token key atrule">back-tier</span><span class="token punctuation">:</span>
    <span class="token key atrule">driver</span><span class="token punctuation">:</span> bridge
</code></pre></div><h4 id="version" tabindex="-1"><a class="header-anchor" href="#version" aria-hidden="true">#</a> version</h4><p>Compose目前有三个版本分别为：</p><ul><li>Version 1</li><li>Version 2</li><li>Version 3</li></ul><p>Compose区分Version 1和Version 2（Compose 1.6.0+，Docker Engine 1.10.0+）。Version 2支持更多的指令。Version 1将来会被弃用。</p><h4 id="image" tabindex="-1"><a class="header-anchor" href="#image" aria-hidden="true">#</a> image</h4><p>image是指定服务的镜像名称或镜像ID。如果镜像在本地不存在，Compose将会尝试拉取镜像。</p><p>services: web: image: hello-world</p><h4 id="build" tabindex="-1"><a class="header-anchor" href="#build" aria-hidden="true">#</a> build</h4><p>服务除了可以基于指定的镜像，还可以基于一份Dockerfile，在使用up启动时执行构建任务，构建标签是build，可以指定Dockerfile所在文件夹的路径。Compose将会利用Dockerfile自动构建镜像，然后使用镜像启动服务容器。 build: /path/to/build/dir 也可以是相对路径，只要上下文确定就可以读取到Dockerfile。 build: ./dir 设定上下文根目录，然后以该目录为准指定Dockerfile。</p><p>build: context: ../ dockerfile: path/of/Dockerfile build都是一个目录，如果要指定Dockerfile文件需要在build标签的子级标签中使用dockerfile标签指定。 如果同时指定image和build两个标签，那么Compose会构建镜像并且把镜像命名为image值指定的名字。</p><h4 id="context" tabindex="-1"><a class="header-anchor" href="#context" aria-hidden="true">#</a> context</h4><p>context选项可以是Dockerfile的文件路径，也可以是到链接到git仓库的url，当提供的值是相对路径时，被解析为相对于撰写文件的路径，此目录也是发送到Docker守护进程的context</p><p>build: context: ./dir</p><h4 id="dockerfile" tabindex="-1"><a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a> dockerfile</h4><p>使用dockerfile文件来构建，必须指定构建路径</p><p>build: context: . dockerfile: Dockerfile-alternate dockerfile指令不能跟image同时使用，否则Compose将不确定根据哪个指令来生成最终的服务镜像。</p><h4 id="command" tabindex="-1"><a class="header-anchor" href="#command" aria-hidden="true">#</a> command</h4><p>使用command可以覆盖容器启动后默认执行的命令。 command: bundle exec thin -p 3000</p><h4 id="container-name" tabindex="-1"><a class="header-anchor" href="#container-name" aria-hidden="true">#</a> container_name</h4><p>Compose的容器名称格式是：&lt;项目名称&gt;&lt;服务名称&gt;&lt;序号&gt; 可以自定义项目名称、服务名称，但如果想完全控制容器的命名，可以使用标签指定： container_name: app</p><h4 id="depends-on" tabindex="-1"><a class="header-anchor" href="#depends-on" aria-hidden="true">#</a> depends_on</h4><p>在使用Compose时，最大的好处就是少打启动命令，但一般项目容器启动的顺序是有要求的，如果直接从上到下启动容器，必然会因为容器依赖问题而启动失败。例如在没启动数据库容器的时候启动应用容器，应用容器会因为找不到数据库而退出。depends_on标签用于解决容器的依赖、启动先后的问题。</p><p>version: &#39;2&#39; services: web: build: . depends_on:</p><ul><li>db</li><li>redis redis: image: redis db: image: postgres 上述YAML文件定义的容器会先启动redis和db两个服务，最后才启动web 服务。</li></ul><h4 id="pid" tabindex="-1"><a class="header-anchor" href="#pid" aria-hidden="true">#</a> pid</h4><p>pid: &quot;host&quot; 将PID模式设置为主机PID模式，跟主机系统共享进程命名空间。容器使用pid标签将能够访问和操纵其他容器和宿主机的名称空间。</p><h4 id="ports" tabindex="-1"><a class="header-anchor" href="#ports" aria-hidden="true">#</a> ports</h4><p>ports用于映射端口的标签。 使用HOST:CONTAINER格式或者只是指定容器的端口，宿主机会随机映射端口。</p><p>ports:</p><ul><li>&quot;3000&quot;</li><li>&quot;8000:8000&quot;</li><li>&quot;49100:22&quot;</li><li>&quot;127.0.0.1:8001:8001&quot; 当使用HOST:CONTAINER格式来映射端口时，如果使用的容器端口小于60可能会得到错误得结果，因为YAML将会解析xx:yy这种数字格式为60进制。所以建议采用字符串格式。</li></ul><h4 id="extra-hosts" tabindex="-1"><a class="header-anchor" href="#extra-hosts" aria-hidden="true">#</a> extra_hosts</h4><p>添加主机名的标签，会在/etc/hosts文件中添加一些记录。</p><p>extra_hosts:</p><ul><li>&quot;somehost:162.242.195.82&quot;</li><li>&quot;otherhost:50.31.209.229&quot; 启动后查看容器内部hosts：</li></ul><p>162.242.195.82 somehost 50.31.209.229 otherhost</p><h4 id="volumes" tabindex="-1"><a class="header-anchor" href="#volumes" aria-hidden="true">#</a> volumes</h4><p>挂载一个目录或者一个已存在的数据卷容器，可以直接使用 [HOST:CONTAINER]格式，或者使用[HOST:CONTAINER:ro]格式，后者对于容器来说，数据卷是只读的，可以有效保护宿主机的文件系统。 Compose的数据卷指定路径可以是相对路径，使用 . 或者 .. 来指定相对目录。 数据卷的格式可以是下面多种形式：</p><p>volumes: // 只是指定一个路径，Docker 会自动在创建一个数据卷（这个路径是容器内部的）。</p><ul><li>/var/lib/mysql // 使用绝对路径挂载数据卷</li><li>/opt/data:/var/lib/mysql // 以 Compose 配置文件为中心的相对路径作为数据卷挂载到容器。</li><li>./cache:/tmp/cache // 使用用户的相对路径（~/ 表示的目录是 /home/&lt;用户目录&gt;/ 或者 /root/）。</li><li>~/configs:/etc/configs/:ro // 已经存在的命名的数据卷。</li><li>datavolume:/var/lib/mysql 如果不使用宿主机的路径，可以指定一个volume_driver。 volume_driver: mydriver</li></ul><h4 id="volumes-from" tabindex="-1"><a class="header-anchor" href="#volumes-from" aria-hidden="true">#</a> volumes_from</h4><p>从另一个服务或容器挂载其数据卷：</p><p>volumes_from:</p><ul><li>service_name <ul><li>container_name 14、dns 自定义DNS服务器。可以是一个值，也可以是一个列表。</li></ul></li></ul><p>dns：8.8.8.8 dns：</p><ul><li>8.8.8.8</li><li>9.9.9.9</li></ul><h4 id="dns-search" tabindex="-1"><a class="header-anchor" href="#dns-search" aria-hidden="true">#</a> dns_search</h4><p>配置DNS搜索域。可以是一个值，也可以是一个列表。</p><p>dns_search：example.com dns_search：</p><ul><li>domain1.example.com</li><li>domain2.example.com</li></ul><h4 id="entrypoint" tabindex="-1"><a class="header-anchor" href="#entrypoint" aria-hidden="true">#</a> entrypoint</h4><p>在Dockerfile中有一个指令叫做ENTRYPOINT指令，用于指定接入点。 在docker-compose.yml中可以定义接入点，覆盖Dockerfile中的定义： entrypoint: /code/entrypoint.sh</p><h4 id="env-file" tabindex="-1"><a class="header-anchor" href="#env-file" aria-hidden="true">#</a> env_file</h4><p>在docker-compose.yml中可以定义一个专门存放变量的文件。 如果通过docker-compose -f FILE指定配置文件，则env_file中路径会使用配置文件路径。 如果有变量名称与environment指令冲突，则以后者为准。格式如下： env_file: .env 或者根据docker-compose.yml设置多个：</p><p>env_file:</p><ul><li>./common.env</li><li>./apps/web.env</li><li>/opt/secrets.env 如果在配置文件中有build操作，变量并不会进入构建过程中。</li></ul><h4 id="cap-add" tabindex="-1"><a class="header-anchor" href="#cap-add" aria-hidden="true">#</a> cap_add</h4><p>增加指定容器的内核能力（capacity）。 让容器具有所有能力可以指定：</p><p>cap_add:</p><ul><li>ALL</li></ul><h4 id="cap-drop" tabindex="-1"><a class="header-anchor" href="#cap-drop" aria-hidden="true">#</a> cap_drop</h4><p>去掉指定容器的内核能力（capacity）。 去掉NET_ADMIN能力可以指定：</p><p>cap_drop:</p><ul><li>NET_ADMIN</li></ul><h4 id="cgroup-parent" tabindex="-1"><a class="header-anchor" href="#cgroup-parent" aria-hidden="true">#</a> cgroup_parent</h4><p>创建了一个cgroup组名称为cgroups_1: cgroup_parent: cgroups_1</p><h4 id="devices" tabindex="-1"><a class="header-anchor" href="#devices" aria-hidden="true">#</a> devices</h4><p>指定设备映射关系，例如：</p><p>devices:</p><ul><li>&quot;/dev/ttyUSB1:/dev/ttyUSB0&quot;</li></ul><h4 id="expose" tabindex="-1"><a class="header-anchor" href="#expose" aria-hidden="true">#</a> expose</h4><p>暴露端口，但不映射到宿主机，只允许能被连接的服务访问。仅可以指定内部端口为参数，如下所示：</p><div class="language-yaml" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">expose</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token string">&quot;3000&quot;</span>
  <span class="token punctuation">-</span> <span class="token string">&quot;8000&quot;</span>
</code></pre></div>`,172),p=[c];function t(l,i){return s(),n("div",null,p)}const u=a(o,[["render",t],["__file","docker-compose.html.vue"]]);export{u as default};
